components.css:
.ds-btn-outline {
  font-family: Poppins, 'Noto Sans SC', Inter, sans-serif;
  font-size: 0.85rem;
  font-weight: 400;
  letter-spacing: 0.05em;
  color: rgba(255, 255, 255, 0.55);
  border: 1px solid rgba(255, 255, 227, 0.3);
  padding: 0.3em 0.9em;
  border-radius: 2px;
  text-decoration: none;
  transition: border-color 0.3s ease, color 0.3s ease;
  background: transparent;
  cursor: pointer;
}
.ds-btn-outline:hover {
  border-color: #FFFFE3;
  color: #FFFFE3;
}

.ds-tag {
  font-family: Poppins, 'Noto Sans SC', Inter, sans-serif;
  font-size: 0.75rem;
  letter-spacing: 0.08em;
  color: #FFFFE3;
  border: 1px solid rgba(255, 255, 227, 0.25);
  padding: 0.5em 1.2em;
  border-radius: 100px;
  background: transparent;
  transition: background 0.3s ease, color 0.3s ease;
  cursor: default;
}
.ds-tag:hover {
  background: #FFFFE3;
  color: #000000;
}

.ds-card {
  position: relative;
  overflow: hidden;
  border-radius: 2px;
  background: #0a0a0a;
  cursor: pointer;
}
.ds-card-image {
  width: 100%;
  height: 100%;
  transition: transform 0.6s cubic-bezier(0.25, 0.1, 0.25, 1);
}
.ds-card-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}
.ds-card:hover .ds-card-image {
  transform: scale(1.03);
}
.ds-card-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(to top, rgba(0,0,0,0.85) 0%, rgba(0,0,0,0.2) 60%, transparent 100%);
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  padding: 1.8rem;
  opacity: 0;
  transition: opacity 0.4s ease;
}
.ds-card:hover .ds-card-overlay {
  opacity: 1;
}
.ds-card-category {
  font-family: Poppins, 'Noto Sans SC', Inter, sans-serif;
  font-size: 0.7rem;
  font-weight: 500;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: #FFFFE3;
  display: block;
  margin-bottom: 0.35rem;
}
.ds-card-title {
  font-family: 'Noto Serif SC', 'Playfair Display', 'Times New Roman', serif;
  font-size: 1.3rem;
  font-weight: 700;
  color: #FFFFFF;
  line-height: 1.2;
  margin: 0;
}

.ds-nav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 100;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1.5rem 3rem;
  transition: background 0.4s ease, backdrop-filter 0.4s ease;
}
.ds-nav-logo {
  font-family: Poppins, 'Noto Sans SC', Inter, sans-serif;
  font-size: 0.8rem;
  font-weight: 500;
  letter-spacing: 0.2em;
  color: #FFFFFF;
  text-decoration: none;
  transition: color 0.3s ease;
}
.ds-nav-logo:hover {
  color: #FFFFE3;
}
.ds-nav-links {
  list-style: none;
  display: flex;
  gap: 2.5rem;
  margin: 0;
  padding: 0;
}
.ds-nav-link {
  font-family: Poppins, 'Noto Sans SC', Inter, sans-serif;
  font-size: 0.85rem;
  font-weight: 400;
  letter-spacing: 0.05em;
  color: rgba(255, 255, 255, 0.55);
  text-decoration: none;
  position: relative;
  padding: 0.3em 0;
  transition: color 0.3s ease;
}
.ds-nav-link::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: 0;
  width: 100%;
  height: 1px;
  background: #FFFFE3;
  transform: scaleX(0);
  transform-origin: right;
  transition: transform 0.35s ease;
}
.ds-nav-link:hover {
  color: #FFFFFF;
}
.ds-nav-link:hover::after {
  transform: scaleX(1);
  transform-origin: left;
}

.ds-contact-link {
  text-decoration: none;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.4rem;
  padding: 0.8rem 0;
  position: relative;
  transition: transform 0.25s ease;
}
.ds-contact-link::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: 0;
  width: 100%;
  height: 1px;
  background: #FFFFE3;
  transform: scaleX(0);
  transform-origin: right;
  transition: transform 0.4s cubic-bezier(0.25, 0.1, 0.25, 1);
}
.ds-contact-link:hover::after {
  transform: scaleX(1);
  transform-origin: left;
}
.ds-contact-label {
  font-size: 0.7rem;
  font-weight: 500;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.55);
}
.ds-contact-value {
  font-family: 'Noto Serif SC', 'Playfair Display', 'Times New Roman', serif;
  font-size: 1.2rem;
  color: #FFFFFF;
  transition: color 0.3s ease;
}
.ds-contact-link:hover .ds-contact-value {
  color: #FFFFE3;
}
